mapper.select:
SELECT next_call_number
FROM business_status
WHERE business_date = #{date}

mapper.update:
UPDATE business_status
SET next_call_number = next_call_number + 1
WHERE business_date = #{date}

UPDATE business_status
SET daily_total_customers = daily_total_customers + #{customerCount}
WHERE business_date = #{date}

mapper.select:
SELECT is_open
FROM business_status
WHERE business_date = #{date}

mapper.update:
UPDATE business_status
SET daily_takeout_count = daily_takeout_count + 1
WHERE business_date = #{date}

UPDATE business_status
SET daily_cancelled_prepaid_amount = daily_cancelled_prepaid_amount + #{amount}
WHERE business_date = #{date}
